import { useVirtualizer } from '@tanstack/react-virtual';
import clsx from 'clsx';
import { type PropsWithChildren, useRef, Children, useEffect } from 'react';

import { itemsList, listContainer } from './VirtualizedTooltipBody.sty.js';
import type { StylingProps } from '../../../../../../core/types/styling-props.js';
import { useBodyHeightStyle } from '../../ChartTooltip/hooks/useBodyHeightStyle.js';
import { ESTIMATED_ITEM_SIZE } from '../../constants.js';
import { container } from '../../shared/styles/TooltipBody.sty.js';
import type { VirtualEstimatedSize } from '../../types/tooltip.js';

export interface VirtualizedTooltipBodyProps extends StylingProps {
  estimatedItemSize?: VirtualEstimatedSize;
  onScrollContent?: (event: Event) => void;
}

export const VirtualizedTooltipBody = (
  props: PropsWithChildren<VirtualizedTooltipBodyProps>,
) => {
  const {
    children,
    estimatedItemSize,
    style: consumerStyle,
    className: consumerClassname,
    onScrollContent,
  } = props;

  const bodyItems = Children.toArray(children);
  const bodyItemsCount = bodyItems.length;

  const scrollRef = useRef<HTMLDivElement>(null);

  const { getVirtualItems, getTotalSize, measureElement } = useVirtualizer({
    count: bodyItemsCount,
    getScrollElement: () => scrollRef.current,
    estimateSize: (index: number) => {
      return estimatedItemSize?.(index) ?? ESTIMATED_ITEM_SIZE;
    },
  });
  const items = getVirtualItems();
  const totalSize = getTotalSize();

  const bodyHeightStyle = useBodyHeightStyle(totalSize, bodyItemsCount);

  useEffect(() => {
    if (!onScrollContent) {
      return;
    }
    const scrollContainer = scrollRef.current;
    scrollContainer?.addEventListener('scroll', onScrollContent);

    return () => {
      scrollContainer?.removeEventListener('scroll', onScrollContent);
    };
  }, [onScrollContent]);

  if (!bodyItemsCount) {
    return null;
  }

  return (
    <div
      className={clsx(container, consumerClassname)}
      ref={scrollRef}
      style={{ ...bodyHeightStyle, ...consumerStyle }}
    >
      <div style={{ height: totalSize }} className={listContainer}>
        <ul
          className={itemsList}
          style={{ transform: `translateY(${items[0]?.start ?? 0}px)` }}
          data-testid="virtualized-items-list"
        >
          {items.map((item) => (
            <li key={item.key} data-index={item.index} ref={measureElement}>
              {bodyItems[item.index]}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};
